    57→  const { data: ackedData, mutate: mutateAcked } = useSWR(
    58→    ["todos-count", "acknowledged", aggregated],
    59→    () => todosApi.list("acknowledged", 1, 1, aggregated)
    60→  );
    61→  const { data: resolvedData, mutate: mutateResolved } = useSWR(
    62→    ["todos-count", "resolved", aggregated],
    63→    () => todosApi.list("resolved", 1, 1, aggregated)
    64→  );
