   673→                style={{ borderColor: "#e8e8e5", color: "#374151", fontFamily: "var(--font-dm-sans)" }}
   674→              >
   675→                Next
   676→              </button>
   677→            </div>
   678→          )}
   679→        </>
   680→      )}
   681→
   682→      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
   683→        <DialogContent className="sm:max-w-lg">
   684→          <DialogHeader>
   685→            <DialogTitle>Create Project</DialogTitle>
   686→          </DialogHeader>
   687→          <ProjectForm
   688→            title="Create Project"
   689→            onSubmit={async (result) => {
   690→              const created = await projectsApi.create(result.project);
   691→              if (result.source && created.data?.id) {
   692→                const res = await sourcesApi.create(created.data.id, result.source);
   693→                if (res.data?.id) sourcesApi.poll(res.data.id).catch(() => {});
   694→              }
   695→            }}
   696→            onSuccess={() => { setCreateOpen(false); mutate("projects"); }}
