   947→// CreateSemanticRelease inserts a semantic release and its source release links
   948→// in a single transaction. The sr.ID field is populated on success.
   949→func (s *PgStore) CreateSemanticRelease(ctx context.Context, sr *models.SemanticRelease, releaseIDs []string) error {
   950→	tx, err := s.pool.Begin(ctx)
   951→	if err != nil {
   952→		return fmt.Errorf("begin tx: %w", err)
   953→	}
   954→	defer tx.Rollback(ctx)
   955→
   956→	err = tx.QueryRow(ctx,
   957→		`INSERT INTO semantic_releases (project_id, version, report, status, completed_at)
   958→		 VALUES ($1, $2, $3, $4, $5)
   959→		 RETURNING id, created_at`,
   960→		sr.ProjectID, sr.Version, sr.Report, sr.Status, sr.CompletedAt,
   961→	).Scan(&sr.ID, &sr.CreatedAt)
   962→	if err != nil {
   963→		return fmt.Errorf("insert semantic release: %w", err)
   964→	}
   965→
   966→	for _, relID := range releaseIDs {
   967→		_, err = tx.Exec(ctx,
   968→			`INSERT INTO semantic_release_sources (semantic_release_id, release_id)
   969→			 VALUES ($1, $2) ON CONFLICT DO NOTHING`,
   970→			sr.ID, relID,
   971→		)
   972→		if err != nil {
   973→			return fmt.Errorf("insert semantic release source: %w", err)
   974→		}
   975→	}
   976→
   977→	return tx.Commit(ctx)
   978→}
