   980→// UpdateAgentRunResult sets the semantic_release_id for a completed agent run.
   981→func (s *PgStore) UpdateAgentRunResult(ctx context.Context, id string, semanticReleaseID string) error {
   982→	tag, err := s.pool.Exec(ctx,
   983→		`UPDATE agent_runs SET semantic_release_id = $1 WHERE id = $2`,
   984→		semanticReleaseID, id,
   985→	)
   986→	if err != nil {
   987→		return fmt.Errorf("update agent run result: %w", err)
   988→	}
   989→	if tag.RowsAffected() == 0 {
   990→		return fmt.Errorf("agent run not found: %s", id)
   991→	}
   992→	return nil
   993→}
