   995→// ListProjectSubscriptions returns all project-level subscriptions for a given project.
   996→func (s *PgStore) ListProjectSubscriptions(ctx context.Context, projectID string) ([]models.Subscription, error) {
   997→	rows, err := s.pool.Query(ctx,
   998→		`SELECT id, channel_id, type, source_id, project_id, COALESCE(version_filter,''), created_at
   999→		 FROM subscriptions
  1000→		 WHERE type = 'semantic_release' AND project_id = $1`, projectID)
  1001→	if err != nil {
  1002→		return nil, fmt.Errorf("list project subscriptions: %w", err)
  1003→	}
  1004→	defer rows.Close()
  1005→	var subs []models.Subscription
  1006→	for rows.Next() {
  1007→		var sub models.Subscription
  1008→		if err := rows.Scan(&sub.ID, &sub.ChannelID, &sub.Type, &sub.SourceID,
  1009→			&sub.ProjectID, &sub.VersionFilter, &sub.CreatedAt); err != nil {
  1010→			return nil, fmt.Errorf("scan subscription: %w", err)
  1011→		}
  1012→		subs = append(subs, sub)
  1013→	}
  1014→	return subs, nil
  1015→}
