   676→		        sr.created_at, sr.completed_at
   677→		 FROM semantic_releases sr
   678→		 LEFT JOIN projects p ON sr.project_id = p.id
   679→		 ORDER BY sr.created_at DESC LIMIT $1 OFFSET $2`, perPage, offset)
