     9→
    10→// Service orchestrates ingestion sources and persists results.
    11→type Service struct {
    12→	store ReleaseStore
    13→}
    14→
    15→func NewService(store ReleaseStore) *Service {
    16→	return &Service{store: store}
    17→}
    18→
    19→// ProcessResults persists raw ingestion results via the store.
    20→// Duplicate releases (unique constraint violations) are logged and skipped, not fatal.
    21→func (s *Service) ProcessResults(ctx context.Context, sourceID string, sourceName string, results []IngestionResult) error {
    22→	for _, r := range results {
    23→		if err := s.store.IngestRelease(ctx, sourceID, &r); err != nil {
    24→			if isUniqueViolation(err) {
    25→				slog.Debug("duplicate release, skipping", "version", r.RawVersion)
    26→				continue
    27→			}
    28→			return fmt.Errorf("ingest %s: %w", r.RawVersion, err)
    29→		}
    30→		slog.Info("ingested release", "source", sourceName, "version", r.RawVersion)
    31→	}
    32→	return nil
    33→}
    34→
    35→// isUniqueViolation checks if the error is a PostgreSQL unique constraint violation.
    36→// pgx wraps the PG error; we check for the SQLSTATE code 23505.
    37→func isUniqueViolation(err error) bool {
    38→	return strings.Contains(err.Error(), "23505") ||
    39→		strings.Contains(err.Error(), "unique_violation")
    40→}
