   218→            onClick={() => setEditingSource(source)}
   219→            className="group/chip inline-flex items-center gap-1.5 rounded px-2 py-0.5 text-[12px] transition-colors hover:bg-[#f0f0ee]"
   220→            style={{
   221→              backgroundColor: "#fafaf9",
   222→              border: "1px solid #e8e8e5",
   223→            }}
   224→          >
   225→            <span
   226→              className="inline-block h-1.5 w-1.5 rounded-full shrink-0"
   227→              style={{ backgroundColor: source.enabled ? "#16a34a" : "#d1d5db" }}
   228→            />
   229→            {(() => { const Icon = getProviderIcon(source.provider); return Icon ? <Icon size={12} className="shrink-0" style={{ color: "#9ca3af" }} /> : null; })()}
   230→            <span style={{ fontFamily: "'JetBrains Mono', monospace", color: "#374151" }}>
   231→              {source.repository}
   232→            </span>
   233→            {source.last_polled_at && (
   234→              <span style={{ color: "#9ca3af" }}>
   235→                {timeAgo(source.last_polled_at).replace(" ago", "")}
   236→              </span>
   237→            )}
   238→            <Pencil className="h-2.5 w-2.5 hidden group-hover/chip:inline shrink-0" style={{ color: "#9ca3af", opacity: 0.5 }} />
   239→          </button>
   240→        ))}
   241→        <button
   242→          onClick={() => setSourceCreateOpen(true)}
   243→          className="inline-flex items-center gap-1 px-2 py-0.5 text-[12px] font-medium rounded border transition-colors hover:bg-[#f3f3f1]"
   244→          style={{
   245→            borderColor: "#e8e8e5",
   246→            color: "#9ca3af",
   247→            fontFamily: "var(--font-dm-sans)",
   248→          }}
   249→        >
   250→          <Plus className="h-3 w-3" />
   251→          Add Source
   252→        </button>
   253→      </div>
   254→
   255→      {/* Releases flow */}
   256→      {releases.length > 0 && (
   257→        <FlowSection label="Releases" moreHref={`/releases?project=${project.id}`}>
   258→          {releases.map((r) => {
   259→            const src = sourceMap.get(r.source_id);
   260→            return (
   261→              <span key={r.id} className="inline-flex items-baseline mr-2.5">
   262→                <Link
   263→                  href={`/releases/${r.id}`}
   264→                  className={r.excluded ? "" : "text-[#2563eb] hover:underline"}
   265→                  style={{
   266→                    fontFamily: "'JetBrains Mono', monospace",
   267→                    fontSize: "12px",
   268→                    ...(r.excluded ? { color: "#c4c4c0" } : {}),
   269→                  }}
   270→                >
   271→                  {r.version}
   272→                </Link>
   273→                {src && (
   274→                  <span
   275→                    className="text-[11px] ml-1 hidden sm:inline"
   276→                    style={{ color: r.excluded ? "#dcdcda" : "#9ca3af" }}
   277→                  >
   278→                    ({src.repository.split("/").pop()})
   279→                  </span>
   280→                )}
   281→                <span
   282→                  className="text-[11px] ml-1"
   283→                  style={{ color: r.excluded ? "#dcdcda" : "#c4c4c0" }}
   284→                >
   285→                  {timeAgo(r.released_at || r.created_at).replace(" ago", "")}
   286→                </span>
   287→              </span>
   288→            );
   289→          })}
   290→        </FlowSection>
   291→      )}
   292→
   293→      {/* Semantic releases */}
   294→      {srItems.length > 0 && (
   295→        <FlowSection label="Semantic Releases" moreHref={`/semantic-releases?project=${project.id}`}>
   296→          {srItems.map((sr) => {
   297→            const urgencyStyle = sr.report?.urgency
   298→              ? URGENCY_COLORS[sr.report.urgency.toLowerCase()]
   299→              : undefined;
   300→            return (
   301→              <span key={sr.id} className="inline-flex items-center gap-1.5 mr-2.5">
   302→                <Link
   303→                  href={`/projects/${project.id}/semantic-releases/${sr.id}`}
   304→                  className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none hover:ring-1 hover:ring-blue-300 transition-shadow"
   305→                  style={{
   306→                    backgroundColor: "#eff6ff",
   307→                    fontFamily: "'JetBrains Mono', monospace",
   308→                    color: "#1d4ed8",
   309→                  }}
   310→                >
   311→                  {sr.version}
   312→                </Link>
   313→                {urgencyStyle && (
   314→                  <span
   315→                    className="rounded px-1.5 py-0.5 text-[10px] uppercase font-bold tracking-wide leading-none"
   316→                    style={{ backgroundColor: urgencyStyle.bg, color: urgencyStyle.text }}
   317→                  >
   318→                    {sr.report?.urgency}
   319→                  </span>
   320→                )}
   321→              </span>
   322→            );
   323→          })}
   324→        </FlowSection>
   325→      )}
   326→
   327→      {/* Add Source dialog */}
   328→      <Dialog open={sourceCreateOpen} onOpenChange={setSourceCreateOpen}>
   329→        <DialogContent className="sm:max-w-lg">
   330→          <DialogHeader>
   331→            <DialogTitle>Add Source</DialogTitle>
   332→          </DialogHeader>
   333→          <SourceForm
   334→            title="Add Source"
   335→            projectId={project.id}
   336→            onSubmit={async (input) => {
   337→              const res = await sourcesApi.create(project.id, input);
   338→              if (res.data?.id) sourcesApi.poll(res.data.id).catch(() => {});
   339→            }}
   340→            onSuccess={() => {
   341→              setSourceCreateOpen(false);
   342→              mutateSources();
   343→            }}
   344→            onCancel={() => setSourceCreateOpen(false)}
   345→          />
   346→        </DialogContent>
   347→      </Dialog>
   348→
   349→      {/* Edit Source dialog */}
   350→      <Dialog
   351→        open={!!editingSource}
   352→        onOpenChange={(open) => { if (!open) setEditingSource(null); }}
   353→      >
   354→        <DialogContent className="sm:max-w-lg">
   355→          <DialogHeader>
   356→            <DialogTitle>Edit Source</DialogTitle>
   357→          </DialogHeader>
   358→          {editingSource && (
   359→            <SourceForm
   360→              key={editingSource.id}
   361→              title="Edit Source"
   362→              initial={editingSource}
   363→              onSubmit={async (input) => {
   364→                await sourcesApi.update(editingSource.id, input);
   365→              }}
   366→              onSuccess={() => {
   367→                setEditingSource(null);
   368→                mutateSources();
   369→              }}
   370→              onCancel={() => setEditingSource(null)}
   371→            />
   372→          )}
   373→        </DialogContent>
   374→      </Dialog>
   375→    </div>
   376→  );
   377→}
   378→
   379→/* ---------- Compact Row ---------- */
   380→
   381→function ProjectCompactRow({ project }: { project: Project }) {
   382→  const router = useRouter();
   383→  const { data: relData } = useSWR(`project-${project.id}-card-releases`, () =>
   384→    releasesApi.listByProject(project.id, 1, 5, true)
   385→  );
   386→  const { data: srcData } = useSWR(`project-${project.id}-card-sources`, () =>
   387→    sourcesApi.listByProject(project.id)
   388→  );
   389→  const { data: srData } = useSWR(`project-${project.id}-card-sr`, () =>
   390→    srApi.list(project.id, 1, 3)
   391→  );
   392→
   393→  const releases = relData?.data ?? [];
   394→  const sources = srcData?.data ?? [];
   395→  const srItems = srData?.data ?? [];
   396→  const latest = releases[0];
   397→  const latestSr = srItems[0];
   398→
   399→  const sourceMap = useMemo(() => {
   400→    const m = new Map<string, Source>();
   401→    for (const s of sources) m.set(s.id, s);
   402→    return m;
   403→  }, [sources]);
   404→
   405→  const latestSrc = latest ? sourceMap.get(latest.source_id) : undefined;
   406→  const latestIcon = latestSrc ? getProviderIcon(latestSrc.provider) : undefined;
   407→
   408→  const urgencyStyle = latestSr?.report?.urgency
   409→    ? URGENCY_COLORS[latestSr.report.urgency.toLowerCase()]
   410→    : undefined;
   411→
   412→  return (
   413→    <div
   414→      onClick={() => router.push(`/projects/${project.id}`)}
   415→      className="flex items-center gap-4 rounded-md px-4 py-2.5 transition-colors hover:bg-[#f9f9f7] cursor-pointer"
   416→      style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
   417→    >
   418→      {/* Project name */}
   419→      <span
   420→        className="flex items-center gap-2 text-[14px] font-bold shrink-0"
   421→        style={{ fontFamily: "var(--font-fraunces)", color: "#e8601a", minWidth: "160px" }}
   422→      >
   423→        <ProjectLogo name={project.name} sources={sources} size={24} />
   424→        {project.name}
   425→      </span>
   426→
   427→      {/* Latest release */}
   428→      <span className="flex items-center gap-1.5 shrink-0" style={{ minWidth: "140px" }}>
   429→        {latest ? (
   430→          <>
   431→            <Link
   432→              href={`/releases/${latest.id}`}
   433→              onClick={(e) => e.stopPropagation()}
   434→              className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none hover:ring-1 hover:ring-gray-300 transition-shadow"
   435→              style={{
   436→                backgroundColor: "#f3f3f1",
   437→                fontFamily: "'JetBrains Mono', monospace",
   438→                color: "#374151",
   439→              }}
   440→            >
   441→              {latest.version}
   442→            </Link>
   443→            {latestIcon && latestIcon({ size: 12, className: "shrink-0", style: { color: "#9ca3af" } })}
   444→          </>
   445→        ) : (
   446→          <span className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
   447→            No releases
   448→          </span>
   449→        )}
   450→      </span>
   451→
   452→      {/* Latest semantic release */}
   453→      <span className="flex items-center gap-1.5 flex-1 min-w-0">
   454→        {latestSr ? (
   455→          <>
   456→            <Link
   457→              href={`/projects/${project.id}/semantic-releases/${latestSr.id}`}
   458→              onClick={(e) => e.stopPropagation()}
   459→              className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none shrink-0 hover:ring-1 hover:ring-blue-300 transition-shadow"
   460→              style={{
   461→                backgroundColor: "#eff6ff",
   462→                fontFamily: "'JetBrains Mono', monospace",
   463→                color: "#1d4ed8",
   464→              }}
   465→            >
   466→              {latestSr.version}
   467→            </Link>
   468→            {urgencyStyle && (
   469→              <span
   470→                className="inline-flex items-center rounded-full px-1.5 py-0.5 text-[10px] font-medium leading-none shrink-0"
   471→                style={{ backgroundColor: urgencyStyle.bg, color: urgencyStyle.text }}
   472→              >
   473→                {latestSr.report?.urgency}
   474→              </span>
   475→            )}
   476→            {latestSr.report?.summary && (
   477→              <span className="text-[11px] truncate" style={{ color: "#9ca3af" }}>
   478→                {latestSr.report.summary.length > 60
   479→                  ? latestSr.report.summary.slice(0, 60) + "\u2026"
   480→                  : latestSr.report.summary}
   481→              </span>
   482→            )}
   483→          </>
   484→        ) : (
   485→          <span className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
   486→            No analysis
   487→          </span>
   488→        )}
   489→      </span>
   490→
   491→      {/* Arrow */}
   492→      <ArrowRight className="h-3.5 w-3.5 shrink-0" style={{ color: "#c4c4c0" }} />
   493→    </div>
   494→  );
   495→}
   496→
   497→/* ---------- Page ---------- */
   498→
   499→export default function ProjectsPage() {
   500→  const [createOpen, setCreateOpen] = useState(false);
   501→  const [viewMode, setViewMode] = useState<"cards" | "compact">("cards");
   502→  const [search, setSearch] = useState("");
   503→  const [sortBy, setSortBy] = useState<"updated" | "added" | "name">("updated");
   504→  const [page, setPage] = useState(1);
   505→  const { data, isLoading } = useSWR("projects", () => projectsApi.list(1, 100));
   506→  const items = data?.data ?? [];
   507→
   508→  const PAGE_SIZE = 12;
   509→  const filtered = search
   510→    ? items.filter((p) => p.name.toLowerCase().includes(search.toLowerCase()))
   511→    : items;
   512→  const sorted = useMemo(() => {
   513→    const arr = [...filtered];
   514→    switch (sortBy) {
   515→      case "updated":
   516→        return arr.sort((a, b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime());
   517→      case "added":
   518→        return arr.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
   519→      case "name":
   520→        return arr.sort((a, b) => a.name.localeCompare(b.name));
   521→    }
   522→  }, [filtered, sortBy]);
   523→  const totalPages = Math.max(1, Math.ceil(sorted.length / PAGE_SIZE));
   524→  const currentPage = Math.min(page, totalPages);
   525→  const paged = sorted.slice((currentPage - 1) * PAGE_SIZE, currentPage * PAGE_SIZE);
   526→
   527→  return (
   528→    <div className="flex flex-col gap-4 fade-in">
   529→      <div className="flex items-center justify-between">
   530→        <div>
   531→          <h1
   532→            style={{
   533→              fontFamily: "var(--font-fraunces)",
   534→              fontSize: "24px",
   535→              fontWeight: 700,
   536→              color: "#111113",
   537→            }}
   538→          >
   539→            Projects
   540→          </h1>
   541→          <p
   542→            className="mt-1 text-[13px] text-[#6b7280]"
   543→            style={{ fontFamily: "var(--font-dm-sans)" }}
   544→          >
   545→            Tracked software projects and their recent releases.
   546→          </p>
   547→        </div>
   548→        <div className="flex items-center gap-2">
   549→          <div className="relative">
   550→            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3.5 w-3.5" style={{ color: "#9ca3af" }} />
   551→            <input
   552→              type="text"
   553→              value={search}
   554→              onChange={(e) => { setSearch(e.target.value); setPage(1); }}
   555→              placeholder="Search projects..."
   556→              className="rounded-md border py-1.5 pl-8 pr-3 text-[13px] w-48"
   557→              style={{ borderColor: "#e8e8e5", fontFamily: "var(--font-dm-sans)", color: "#374151" }}
   558→            />
   559→          </div>
   560→          <div className="flex items-center gap-1.5 rounded-md border px-2.5 py-1.5 text-[13px]" style={{ borderColor: "#e8e8e5", fontFamily: "var(--font-dm-sans)", color: "#374151" }}>
   561→            <ArrowUpDown className="h-3.5 w-3.5 shrink-0" style={{ color: "#9ca3af" }} />
   562→            <select
   563→              value={sortBy}
   564→              onChange={(e) => { setSortBy(e.target.value as "updated" | "added" | "name"); setPage(1); }}
   565→              className="bg-transparent outline-none cursor-pointer text-[13px]"
   566→              style={{ fontFamily: "var(--font-dm-sans)", color: "#374151" }}
   567→            >
   568→              <option value="updated">Recently updated</option>
   569→              <option value="added">Recently added</option>
   570→              <option value="name">Name</option>
   571→            </select>
   572→          </div>
   573→          <div className="flex items-center rounded-md border" style={{ borderColor: "#e8e8e5" }}>
   574→            <button
   575→              onClick={() => setViewMode("cards")}
   576→              className="p-1.5 rounded-l-md transition-colors"
   577→              style={{
   578→                backgroundColor: viewMode === "cards" ? "#f3f3f1" : "transparent",
   579→                color: viewMode === "cards" ? "#111113" : "#9ca3af",
   580→              }}
   581→              title="Card view"
   582→            >
   583→              <LayoutGrid className="h-4 w-4" />
   584→            </button>
   585→            <button
   586→              onClick={() => setViewMode("compact")}
   587→              className="p-1.5 rounded-r-md transition-colors"
   588→              style={{
   589→                backgroundColor: viewMode === "compact" ? "#f3f3f1" : "transparent",
   590→                color: viewMode === "compact" ? "#111113" : "#9ca3af",
   591→              }}
   592→              title="Compact view"
   593→            >
   594→              <List className="h-4 w-4" />
   595→            </button>
   596→          </div>
   597→          <button
   598→            onClick={() => setCreateOpen(true)}
   599→            className="flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90"
   600→            style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   601→          >
   602→            <Plus className="h-3.5 w-3.5" />
   603→            New Project
   604→          </button>
   605→        </div>
   606→      </div>
   607→
   608→      {isLoading ? (
   609→        <p
   610→          className="px-4 py-8 text-center text-[14px] italic text-[#9ca3af]"
   611→          style={{ fontFamily: "var(--font-fraunces)" }}
   612→        >
   613→          Loading...
   614→        </p>
   615→      ) : items.length === 0 ? (
   616→        <div
   617→          className="flex flex-col items-center justify-center rounded-md border py-12"
   618→          style={{ borderColor: "#e8e8e5", backgroundColor: "#ffffff" }}
   619→        >
   620→          <p
   621→            className="text-[14px] italic text-[#9ca3af]"
   622→            style={{ fontFamily: "var(--font-fraunces)" }}
   623→          >
   624→            No projects yet — create one to start tracking releases
   625→          </p>
   626→          <button
   627→            onClick={() => setCreateOpen(true)}
   628→            className="mt-4 flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90"
   629→            style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   630→          >
   631→            <Plus className="h-3.5 w-3.5" />
   632→            New Project
   633→          </button>
   634→        </div>
   635→      ) : filtered.length === 0 ? (
   636→        <p
   637→          className="px-4 py-8 text-center text-[14px] italic text-[#9ca3af]"
   638→          style={{ fontFamily: "var(--font-fraunces)" }}
   639→        >
   640→          No projects matching &ldquo;{search}&rdquo;
   641→        </p>
   642→      ) : (
   643→        <>
   644→          <div className={viewMode === "cards" ? "space-y-5" : "space-y-1.5"}>
   645→            {paged.map((project) =>
   646→              viewMode === "cards" ? (
   647→                <ProjectFlowCard key={project.id} project={project} />
   648→              ) : (
   649→                <ProjectCompactRow key={project.id} project={project} />
   650→              )
   651→            )}
   652→          </div>
   653→          {totalPages > 1 && (
   654→            <div className="flex items-center justify-center gap-3 pt-2">
   655→              <button
   656→                onClick={() => setPage((p) => Math.max(1, p - 1))}
   657→                disabled={currentPage <= 1}
   658→                className="rounded-md border px-3 py-1 text-[13px] transition-colors disabled:opacity-40"
   659→                style={{ borderColor: "#e8e8e5", color: "#374151", fontFamily: "var(--font-dm-sans)" }}
   660→              >
   661→                Previous
   662→              </button>
   663→              <span
   664→                className="text-[13px]"
   665→                style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}
   666→              >
   667→                Page {currentPage} of {totalPages}
   668→              </span>
   669→              <button
   670→                onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
   671→                disabled={currentPage >= totalPages}
   672→                className="rounded-md border px-3 py-1 text-[13px] transition-colors disabled:opacity-40"
   673→                style={{ borderColor: "#e8e8e5", color: "#374151", fontFamily: "var(--font-dm-sans)" }}
   674→              >
   675→                Next
   676→              </button>
   677→            </div>
   678→          )}
   679→        </>
   680→      )}
   681→
   682→      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
   683→        <DialogContent className="sm:max-w-lg">
   684→          <DialogHeader>
   685→            <DialogTitle>Create Project</DialogTitle>
   686→          </DialogHeader>
   687→          <ProjectForm
   688→            title="Create Project"
   689→            onSubmit={async (result) => {
   690→              const created = await projectsApi.create(result.project);
   691→              if (result.source && created.data?.id) {
   692→                const res = await sourcesApi.create(created.data.id, result.source);
   693→                if (res.data?.id) sourcesApi.poll(res.data.id).catch(() => {});
   694→              }
   695→            }}
   696→            onSuccess={() => { setCreateOpen(false); mutate("projects"); }}
   697→            onCancel={() => setCreateOpen(false)}
   698→          />
   699→        </DialogContent>
   700→      </Dialog>
   701→    </div>
   702→  );
   703→}
