   539→          </div>
   540→        )}
   541→
   542→        {/* --- Semantic Release Settings tab --- */}
   543→        {activeTab === "agent" && (
   544→          <div className="space-y-6">
   545→            {/* Card 1: Trigger Rules */}
   546→            <div
   547→              className="rounded-lg border p-5"
   548→              style={{ borderColor: "#e8e8e5", backgroundColor: "#ffffff" }}
   549→            >
   550→              <SectionLabel className="mb-1">Trigger Rules</SectionLabel>
   551→              <p className="mb-4 text-[12px]" style={{ color: "#9ca3af" }}>
