    95→      <h1
    96→        style={{
    97→          fontFamily: "var(--font-fraunces)",
    98→          fontSize: "24px",
    99→          fontWeight: 700,
   100→          color: "#111113",
   101→        }}
   102→      >
   103→        Semantic Releases
   104→      </h1>
   105→
   106→      {/* Project filter */}
   107→      <div>
   108→        <select
   109→          value={projectFilter}
   110→          onChange={(e) => {
