   667→func (s *PgStore) ListAllSemanticReleases(ctx context.Context, page, perPage int) ([]models.SemanticRelease, int, error) {
   668→	var total int
   669→	err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM semantic_releases`).Scan(&total)
   670→	if err != nil {
   671→		return nil, 0, fmt.Errorf("count semantic releases: %w", err)
   672→	}
   673→	offset := (page - 1) * perPage
   674→	rows, err := s.pool.Query(ctx,
   675→		`SELECT sr.id, sr.project_id, COALESCE(p.name,''), sr.version, COALESCE(sr.report,'{}'), sr.status, COALESCE(sr.error,''),
   676→		        sr.created_at, sr.completed_at
   677→		 FROM semantic_releases sr
   678→		 LEFT JOIN projects p ON sr.project_id = p.id
   679→		 ORDER BY sr.created_at DESC LIMIT $1 OFFSET $2`, perPage, offset)
   680→	if err != nil {
   681→		return nil, 0, fmt.Errorf("list all semantic releases: %w", err)
   682→	}
   683→	defer rows.Close()
   684→	var releases []models.SemanticRelease
   685→	for rows.Next() {
   686→		var sr models.SemanticRelease
   687→		if err := rows.Scan(&sr.ID, &sr.ProjectID, &sr.ProjectName, &sr.Version, &sr.Report, &sr.Status, &sr.Error,
   688→			&sr.CreatedAt, &sr.CompletedAt); err != nil {
   689→			return nil, 0, fmt.Errorf("scan semantic release: %w", err)
   690→		}
   691→		releases = append(releases, sr)
   692→	}
   693→	return releases, total, nil
   694→}
